class Playground {
    async run(inputs) {
        const hArr = JSON.parse(inputs[0]);
        await this.heights.init(hArr);

        let left = 0;
        let right = hArr.length - 1;
        let maxArea = 0;

        await this.vars.init([
            ["left", left],
            ["right", right],
            ["maxArea", maxArea],
            ["currentArea", 0]
        ]);

        while (left < right) {
            const hL = this.heights.get(left);
            const hR = this.heights.get(right);
            const width = right - left;
            const currentHeight = Math.min(hL, hR);
            const currentArea = width * currentHeight;

            // Highlight the two pointers
            this.heights.highlight(left, "#00e0ff");
            this.heights.highlight(right, "#00e0ff");

            if (currentArea > maxArea) {
                maxArea = currentArea;
            }

            // Update state visualization
            this.vars.put("left", left);
            this.vars.put("right", right);
            this.vars.put("currentArea", currentArea);
            this.vars.put("maxArea", maxArea);

            this.log(`Checking indices ${left} and ${right}. Width: ${width}, Min Height: ${currentHeight}, Area: ${currentArea}`);
            await this.await();

            // Clear highlights for next step
            this.heights.highlight(left, null);
            this.heights.highlight(right, null);

            // Move the pointer pointing to the shorter line
            if (hL < hR) {
                this.log(`Height at left (${hL}) < height at right (${hR}). Moving left pointer inward.`);
                left++;
            } else {
                this.log(`Height at right (${hR}) <= height at left (${hL}). Moving right pointer inward.`);
                right--;
            }

            this.vars.put("left", left);
            this.vars.put("right", right);
        }

        this.log(`Algorithm finished. Maximum area found: ${maxArea}`);
        return maxArea;
    }
}
